{"title":"Add error handling","explanation":"Wrap database calls in try/catch blocks to prevent unhandled promise rejections.","diff":"diff --git a/src/db.ts b/src/db.ts
index 2345678..bcdefgh 100644
--- a/src/db.ts
+++ b/src/db.ts
@@ -10,7 +10,12 @@
 export async function getUser(id: string) {
-  const user = await db.query('SELECT * FROM users WHERE id = $1', [id]);
-  return user.rows[0];
+  try {
+    const user = await db.query('SELECT * FROM users WHERE id = $1', [id]);
+    return user.rows[0];
+  } catch (error) {
+    console.error('Failed to fetch user:', error);
+    throw new DatabaseError('User lookup failed', { cause: error });
+  }
 }"}
